const orders = $input.first().json.orders || [];
const now = new Date();
const results = [];

for (const order of orders) {
  const createdAt = new Date(order.created_at);
  const ageMs = now - createdAt;
  const ageDays = Math.floor(ageMs / (1000 * 60 * 60 * 24));

  const customerName = order.customer
    ? ((order.customer.first_name || '') + ' ' + (order.customer.last_name || '')).trim()
    : (order.shipping_address ? order.shipping_address.name : 'Unknown');

  const customerEmail = order.email || (order.customer ? order.customer.email : '') || 'N/A';

  const itemSummary = (order.line_items || []).slice(0, 2).map(i => i.name).join(', ')
    + ((order.line_items || []).length > 2 ? ' +' + ((order.line_items || []).length - 2) + ' more' : '');

  results.push({
    json: {
      orderId: order.id,
      orderNumber: '#' + order.order_number,
      customerName,
      customerEmail,
      total: parseFloat(order.total_price || 0).toFixed(2),
      ageDays,
      createdAt: order.created_at,
      itemSummary,
      orderUrl: 'https://YOUR_STORE.myshopify.com/admin/orders/' + order.id,
      detectedAt: now.toISOString().split('T')[0]
    }
  });
}

return results.length > 0 ? results : [{ json: { _empty: true, ageDays: -1 } }];

const orders = $input.first().json.data || [];

const escalation = orders.filter(o => o.severity === 'ESCALATION');
const critical = orders.filter(o => o.severity === 'CRITICAL');
const warning = orders.filter(o => o.severity === 'WARNING');

const formatOrders = (list) => list.map(o =>
  '- ' + o.orderNumber + ' | ' + o.customerName + ' | $' + o.total + ' | ' + o.ageDays + ' days | ' + o.itemSummary
).join('\n');

let message = ':package: *Shopify Fulfillment Delay Report* | ' + new Date().toISOString().split('T')[0] + '\n';
message += '*Total Delayed Orders: ' + orders.length + '*\n';
message += '---\n';

if (escalation.length > 0) {
  message += '\n:rotating_light: *ESCALATION - 8+ Days (' + escalation.length + ' orders)*\n';
  message += formatOrders(escalation) + '\n';
}
if (critical.length > 0) {
  message += '\n:red_circle: *CRITICAL - 5-7 Days (' + critical.length + ' orders)*\n';
  message += formatOrders(critical) + '\n';
}
if (warning.length > 0) {
  message += '\n:large_yellow_circle: *WARNING - 2-4 Days (' + warning.length + ' orders)*\n';
  message += formatOrders(warning) + '\n';
}

message += '\n_Review and action all delayed orders in Shopify Admin._';

return [{ json: { slackMessage: message, orders, totalCount: orders.length, escalationCount: escalation.length, criticalCount: critical.length, warningCount: warning.length } }];
